const http = require('http');
const fs = require('fs');
const path = require('path');
const { URL } = require('url');

function express() {
  const middlewares = [];
  const routes = [];

  function app(req, res) {
    enhanceResponse(res);
    const parsedUrl = new URL(req.url, `http://${req.headers.host || 'localhost'}`);
    req.path = parsedUrl.pathname;
    req.query = Object.fromEntries(parsedUrl.searchParams.entries());

    const stack = [...middlewares, matchRoute(routes, req)];
    let index = 0;

    function next(err) {
      const layer = stack[index++];
      if (err) {
        res.statusCode = 500;
        res.end(JSON.stringify({ error: 'Internal server error' }));
        return;
      }
      if (!layer) {
        res.statusCode = 404;
        res.end('Not found');
        return;
      }
      layer(req, res, next);
    }

    next();
  }

  app.use = function use(pathOrFn, maybeFn) {
    if (typeof pathOrFn === 'string' && typeof maybeFn === 'function') {
      const basePath = pathOrFn;
      middlewares.push((req, res, next) => {
        if (!req.path.startsWith(basePath)) return next();
        return maybeFn(req, res, next);
      });
      return app;
    }

    middlewares.push(pathOrFn);
    return app;
  };

  ['GET', 'POST'].forEach((method) => {
    app[method.toLowerCase()] = (routePath, handler) => {
      routes.push({ method, routePath, handler });
      return app;
    };
  });

  app.listen = function listen(port, callback) {
    const server = http.createServer(app);
    return server.listen(port, callback);
  };

  return app;
}

function enhanceResponse(res) {
  res.status = function status(code) {
    res.statusCode = code;
    return res;
  };

  res.json = function json(payload) {
    if (!res.headersSent) {
      res.setHeader('Content-Type', 'application/json; charset=utf-8');
    }
    res.end(JSON.stringify(payload));
  };

  res.send = function send(payload) {
    if (typeof payload === 'object' && payload !== null) {
      return res.json(payload);
    }
    res.end(String(payload));
  };
}

function matchRoute(routes, req) {
  return (req2, res, next) => {
    const route = routes.find((entry) => {
      if (entry.method !== req.method) return false;
      const matched = matchPath(entry.routePath, req.path);
      if (!matched) return false;
      req.params = matched;
      return true;
    });
    if (!route) return next();
    return route.handler(req2, res, next);
  };
}

function matchPath(routePath, actualPath) {
  if (routePath === actualPath) return {};
  const routeParts = routePath.split('/').filter(Boolean);
  const actualParts = actualPath.split('/').filter(Boolean);
  if (routeParts.length !== actualParts.length) return null;
  const params = {};
  for (let index = 0; index < routeParts.length; index += 1) {
    const routePart = routeParts[index];
    const actualPart = actualParts[index];
    if (routePart.startsWith(':')) {
      params[routePart.slice(1)] = actualPart;
      continue;
    }
    if (routePart !== actualPart) return null;
  }
  return params;
}

express.json = function json() {
  return (req, res, next) => {
    if (req.method === 'GET') return next();
    const contentType = req.headers['content-type'] || '';
    if (!contentType.includes('application/json')) return next();
    collectBody(req, (rawBody) => {
      if (!rawBody) {
        req.body = {};
        return next();
      }
      try {
        req.body = JSON.parse(rawBody);
        return next();
      } catch (error) {
        res.statusCode = 400;
        return res.json({ error: 'Invalid JSON body' });
      }
    });
  };
};

express.urlencoded = function urlencoded() {
  return (req, res, next) => {
    if (req.method === 'GET') return next();
    const contentType = req.headers['content-type'] || '';
    if (!contentType.includes('application/x-www-form-urlencoded')) return next();
    collectBody(req, (rawBody) => {
      req.body = Object.fromEntries(new URLSearchParams(rawBody));
      next();
    });
  };
};

express.static = function staticMiddleware(rootDir) {
  const resolvedRoot = path.resolve(rootDir);
  return (req, res, next) => {
    if (!['GET', 'HEAD'].includes(req.method)) return next();
    let requestedPath = req.path === '/' ? '/index.html' : req.path;
    const filePath = path.resolve(path.join(resolvedRoot, requestedPath.replace(/^\/+/, '')));
    if (!filePath.startsWith(resolvedRoot)) {
      res.statusCode = 403;
      return res.end('Forbidden');
    }
    fs.stat(filePath, (error, stat) => {
      if (error || !stat.isFile()) return next();
      const ext = path.extname(filePath).toLowerCase();
      const contentType = {
        '.html': 'text/html; charset=utf-8',
        '.css': 'text/css; charset=utf-8',
        '.js': 'application/javascript; charset=utf-8',
        '.json': 'application/json; charset=utf-8',
      }[ext] || 'application/octet-stream';
      res.setHeader('Content-Type', contentType);
      fs.createReadStream(filePath).pipe(res);
    });
  };
};

function collectBody(req, callback) {
  let raw = '';
  req.on('data', (chunk) => {
    raw += chunk;
  });
  req.on('end', () => callback(raw));
}

module.exports = express;
